'use server'

import { revalidatePath } from 'next/cache'
import { redirect } from 'next/navigation'
import { createClient } from '@/lib/supabase/server'

export async function login(formData: FormData) {
  const supabase = await createClient()

  const data = {
    email: formData.get('email') as string,
    password: formData.get('password') as string,
  }

  const { data: { user }, error } = await supabase.auth.signInWithPassword(data)

  if (error || !user) {
    return { error: error?.message || 'Login failed' }
  }

  // Check for admin status
  const { data: profile } = await (supabase.from('profiles') as any)
    .select('is_admin')
    .eq('id', user.id)
    .single()

  revalidatePath('/', 'layout')

  if (profile?.is_admin) {
    redirect('/admin')
  }

  redirect('/studio')
}

export async function signup(formData: FormData) {
  const supabase = await createClient()

  const data = {
    email: formData.get('email') as string,
    password: formData.get('password') as string,
    options: {
      data: {
        full_name: formData.get('full_name') as string,
      }
    }
  }

  const { data: { user }, error } = await supabase.auth.signUp(data)

  if (error || !user) {
    return { error: error?.message || 'Sign up failed' }
  }

  // Admin check (Unlikely for signup, but good for consistency)
  const { data: profile } = await (supabase.from('profiles') as any)
    .select('is_admin')
    .eq('id', user.id)
    .single()

  revalidatePath('/', 'layout')

  if (profile?.is_admin) {
    redirect('/admin')
  }

  redirect('/studio')
}

export async function signout() {
  const supabase = await createClient()
  await supabase.auth.signOut()
  redirect('/')
}
export async function requestPasswordReset(formData: FormData) {
  const supabase = await createClient()
  const email = formData.get('email') as string
  const origin = formData.get('origin') as string

  const { error } = await supabase.auth.resetPasswordForEmail(email, {
    redirectTo: `${origin}/auth/confirm?next=/reset-password`,
  })

  if (error) {
    return { error: error.message }
  }

  return { success: true }
}

export async function updatePassword(formData: FormData) {
  const supabase = await createClient()
  const password = formData.get('password') as string

  const { data: { user }, error } = await supabase.auth.updateUser({
    password: password,
  })

  if (error || !user) {
    return { error: error?.message || 'Update failed' }
  }

  // Check for admin status
  const { data: profile } = await (supabase.from('profiles') as any)
    .select('is_admin')
    .eq('id', user.id)
    .single()

  revalidatePath('/', 'layout')

  if (profile?.is_admin) {
    redirect('/admin')
  }

  redirect('/studio')
}

export default function AuthLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return (
    <div className="min-h-screen flex items-center justify-center bg-background relative overflow-hidden font-sans">
      {/* Background with Hero Image */}
      <div className="absolute inset-0 z-0">
        <img 
          src="/hero-bg.png" 
          className="w-full h-full object-cover opacity-20" 
          alt="Background" 
        />
        <div className="absolute inset-0 bg-gradient-to-b from-background via-black/40 to-background" />
      </div>

      {/* Decorative Glows */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-primary/20 blur-[100px] rounded-full opacity-30 pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-orange-500/10 blur-[100px] rounded-full opacity-20 pointer-events-none" />

      <div className="relative z-10 w-full flex justify-center">
        {children}
      </div>
    </div>
  )
}

'use client'

import { useActionState } from 'react'
import { updatePassword } from '../actions'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card'
import Link from 'next/link'
import { Sparkles, KeyRound } from 'lucide-react'

const updateAction = async (prevState: any, formData: FormData) => {
  const result = await updatePassword(formData)
  if (result?.error) {
    return { error: result.error }
  }
  return { error: null }
}

export default function ResetPasswordPage() {
  const [state, formAction, isPending] = useActionState(updateAction, { error: null })

  return (
    <Card className="w-full max-w-md mx-4 shadow-xl border-primary/20">
      <CardHeader className="space-y-4 text-center pb-6">
        <Link href="/" className="flex items-center justify-center gap-2 group w-fit mx-auto cursor-pointer">
          <Sparkles className="w-5 h-5 text-primary group-hover:scale-110 transition-transform" />
          <span className="font-bold tracking-tight">ViralUGC</span>
        </Link>
        <div className="space-y-1">
          <CardTitle className="text-2xl font-bold flex items-center justify-center gap-2">
            <KeyRound className="w-6 h-6 text-primary" /> New Password
          </CardTitle>
          <CardDescription>Enter your new secure password below</CardDescription>
        </div>
      </CardHeader>

      <form action={formAction}>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="password">New Password</Label>
            <Input id="password" name="password" type="password" placeholder="••••••••" required minLength={6} />
          </div>

          {state?.error && (
            <div className="text-sm font-medium text-destructive bg-destructive/10 p-3 rounded-md">
              {state.error}
            </div>
          )}
        </CardContent>
        <CardFooter className="flex flex-col gap-4">
          <Button type="submit" className="w-full" disabled={isPending}>
            {isPending ? 'Updating...' : 'Set New Password'}
          </Button>
        </CardFooter>
      </form>
    </Card>
  )
}

'use server'

import { createClient } from '@/lib/supabase/server'
import { createAdminClient } from '@/lib/supabase/admin'
import { revalidatePath } from 'next/cache'
import { redirect } from 'next/navigation'

export async function createManualUser(formData: FormData): Promise<{ success: boolean; message: string }> {
  if (!(await verifyAdmin())) return { success: false, message: 'Unauthorized' }

  const email = formData.get('email') as string
  const password = formData.get('password') as string
  const credits = parseInt(formData.get('credits') as string, 10) || 0

  if (!email || !password) return { success: false, message: 'Missing email or password' }

  try {
    const adminClient = createAdminClient()

    // 1. Create the user in auth.users
    const { data: userData, error: userError } = await adminClient.auth.admin.createUser({
      email,
      password,
      email_confirm: true
    })

    if (userError) return { success: false, message: userError.message }

    // 2. Set credits
    const { error: profileError } = await (adminClient.from('profiles') as any)
      .update({ credits })
      .eq('id', userData.user.id)

    if (profileError) throw profileError

    // 3. Log the credit addition
    const { data: { user: admin } } = await (await createClient()).auth.getUser()
    const { error: logError } = await (adminClient.from('credit_logs') as any)
      .insert({
        user_id: userData.user.id,
        amount: credits,
        reason: 'Manual Account Creation',
        admin_id: admin?.id
      })

    if (logError) throw logError

    revalidatePath('/admin')
    return { success: true, message: 'User created successfully!' }
  } catch (err: any) {
    return { success: false, message: err.message || 'An unexpected error occurred' }
  }
}

async function verifyAdmin() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return false

  const { data: profile } = await (supabase.from('profiles') as any)
    .select('is_admin')
    .eq('id', user.id)
    .single()

  return profile?.is_admin === true
}

export async function updateUserCredits(formData: FormData): Promise<{ success: boolean; message: string }> {
  if (!(await verifyAdmin())) return { success: false, message: 'Unauthorized' }

  const userId = formData.get('userId') as string
  const credits = parseInt(formData.get('credits') as string, 10)

  if (!userId || isNaN(credits)) return { success: false, message: 'Invalid data' }

  try {
    const supabase = await createClient()

    // Get current credits for delta calculation
    const { data: profile, error: profileFetchError } = await (supabase.from('profiles') as any).select('credits').eq('id', userId).single()
    if (profileFetchError) throw profileFetchError

    const delta = profile ? credits - profile.credits : 0

    const { error: updateError } = await (supabase.from('profiles') as any)
      .update({ credits })
      .eq('id', userId)

    if (updateError) throw updateError

    // Log the change
    const { data: { user: admin } } = await supabase.auth.getUser()
    const { error: logError } = await (supabase.from('credit_logs') as any)
      .insert({
        user_id: userId,
        amount: delta,
        reason: 'Manual Administrative Adjustment',
        admin_id: admin?.id
      })

    if (logError) throw logError

    revalidatePath('/admin')
    return { success: true, message: 'Credits updated!' }
  } catch (err: any) {
    return { success: false, message: err.message || 'An unexpected error occurred' }
  }
}

export async function toggleAdminStatus(formData: FormData): Promise<{ success: boolean; message: string }> {
  if (!(await verifyAdmin())) return { success: false, message: 'Unauthorized' }

  const userId = formData.get('userId') as string
  const isAdmin = formData.get('isAdmin') === 'true'

  if (!userId) return { success: false, message: 'User ID is required' }

  try {
    const supabase = await createClient()
    const { error } = await (supabase.from('profiles') as any)
      .update({ is_admin: !isAdmin }) // Toggle the current state
      .eq('id', userId)

    if (error) throw error

    revalidatePath('/admin')
    return { success: true, message: 'Admin status toggled!' }
  } catch (err: any) {
    return { success: false, message: err.message || 'An unexpected error occurred' }
  }
}

export async function deleteVideo(formData: FormData): Promise<{ success: boolean; message: string }> {
  if (!(await verifyAdmin())) return { success: false, message: 'Unauthorized' }

  const videoId = formData.get('videoId') as string

  if (!videoId) return { success: false, message: 'Video ID is required' }

  try {
    const supabase = await createClient()
    const { error } = await (supabase.from('videos') as any)
      .delete()
      .eq('id', videoId)

    if (error) throw error

    revalidatePath('/admin')
    return { success: true, message: 'Video deleted!' }
  } catch (err: any) {
    return { success: false, message: err.message || 'An unexpected error occurred' }
  }
}

export async function refundVideo(formData: FormData): Promise<{ success: boolean; message: string }> {
  if (!(await verifyAdmin())) return { success: false, message: 'Unauthorized' }

  const videoId = formData.get('videoId') as string
  const userId = formData.get('userId') as string

  if (!videoId || !userId) return { success: false, message: 'Video ID and User ID are required' }

  try {
    const supabase = await createClient()

    // 1. Mark video as failed
    const { error: updateError } = await (supabase.from('videos') as any)
      .update({ status: 'failed' })
      .eq('id', videoId)

    if (updateError) throw updateError

    // 2. Add credits back to user atomically
    const { data: video } = await (supabase.from('videos') as any).select('duration').eq('id', videoId).single()
    const refundAmount = video?.duration === 30 ? 2 : (video?.duration === 60 ? 4 : 1)

    const { error: rpcError } = await (supabase as any).rpc('increment_credits', { 
      p_user_id: userId, 
      p_amount: refundAmount 
    })

    if (rpcError) throw rpcError

    revalidatePath('/admin')
    return { success: true, message: 'Video refunded!' }
  } catch (err: any) {
    return { success: false, message: err.message || 'An unexpected error occurred' }
  }
}

export async function bulkRefundStuckVideos(): Promise<{ success: boolean; message: string }> {
  if (!(await verifyAdmin())) return { success: false, message: 'Unauthorized' }

  try {
    const supabase = await createClient()
    const fifteenMinutesAgo = new Date(Date.now() - 15 * 60 * 1000).toISOString()

    const { data: stuckVideos } = await (supabase.from('videos') as any)
      .select('id, user_id, duration')
      .in('status', ['pending', 'processing'])
      .lt('created_at', fifteenMinutesAgo)

    if (!stuckVideos || stuckVideos.length === 0) {
      return { success: true, message: 'No stuck videos found.' }
    }

    let count = 0
    for (const video of stuckVideos) {
      const refundAmount = video.duration === 30 ? 2 : (video.duration === 60 ? 4 : 1)

      await (supabase.from('videos') as any).update({ status: 'failed' }).eq('id', video.id)

      await (supabase as any).rpc('increment_credits', { 
        p_user_id: video.user_id, 
        p_amount: refundAmount 
      })

      count++
    }

    revalidatePath('/admin')
    return { success: true, message: `Successfully refunded ${count} videos.` }
  } catch (err: any) {
    return { success: false, message: err.message || 'An unexpected error occurred' }
  }
}

import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'

export const dynamic = 'force-dynamic'

export default async function AdminLayout({
  children,
}: {
  children: React.ReactNode
}) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    redirect('/login')
  }

  const { data: profile, error } = await (supabase.from('profiles') as any)
    .select('is_admin')
    .eq('id', user.id)
    .single()

  if (error || !profile?.is_admin) {
    // If not an admin, redirect to the user's dashboard (studio)
    redirect('/studio')
  }

  return <>{children}</>
}

'use client'

import { createClient } from '@/lib/supabase/client'
import { Card, CardContent, CardFooter, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Download, Copy, Play, Loader2 } from 'lucide-react'
import { Badge } from '@/components/ui/badge'
import { toast } from 'sonner'
import Link from 'next/link'
import { useEffect, useState } from 'react'

export default function GalleryPage() {
  const [videos, setVideos] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function fetchVideos() {
      const supabase = createClient()
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) return

      const { data } = await (supabase.from('videos') as any)
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false })

      if (data) setVideos(data)
      setLoading(false)
    }
    fetchVideos()
  }, [])

  if (loading) return (
    <div className="h-[60vh] flex items-center justify-center">
      <Loader2 className="w-8 h-8 animate-spin text-primary" />
    </div>
  )

  if (!videos || videos.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-[60vh] text-center space-y-4">
        <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center">
          <Play className="w-8 h-8 text-muted-foreground" />
        </div>
        <h2 className="text-2xl font-bold">No videos yet</h2>
        <p className="text-muted-foreground max-w-sm">Generate your first AI Video Ad in the Studio to see it appear here.</p>
        <Link href="/studio">
          <Button>Go to Studio</Button>
        </Link>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold tracking-tight">Your Ads Gallery</h1>
        <Badge variant="outline">{videos.length} Videos</Badge>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {videos.map((video) => (
          <Card key={video.id} className="overflow-hidden shadow-sm hover:shadow-md transition-shadow">
            <div className="aspect-[9/16] bg-black relative group">
              {video.status === 'completed' && video.video_url ? (
                <video src={video.video_url} controls className="w-full h-full object-cover" />
              ) : (
                <div className="absolute inset-0 flex flex-col items-center justify-center bg-muted text-muted-foreground">
                  <Badge variant={video.status === 'failed' ? 'destructive' : 'secondary'} className="mb-2">
                    {video.status.toUpperCase()}
                  </Badge>
                  {video.status !== 'failed' && <span className="text-sm">Processing...</span>}
                </div>
              )}
            </div>
            <CardHeader className="p-4 pb-2">
              <CardTitle className="text-base line-clamp-2" title={video.prompt}>
                {video.prompt}
              </CardTitle>
            </CardHeader>
            <CardContent className="p-4 pt-0">
              <div className="text-xs text-muted-foreground mt-1">
                {video.duration}s • {new Date(video.created_at).toLocaleDateString()}
              </div>
            </CardContent>
            {video.status === 'completed' && video.video_url && (
              <CardFooter className="p-4 pt-0 gap-2">
                <a href={video.video_url} download target="_blank" rel="noreferrer" className="w-full">
                  <Button variant="outline" size="sm" className="w-full">
                    <Download className="w-4 h-4 mr-2" /> Download
                  </Button>
                </a>
                <Button 
                  variant="secondary" 
                  size="icon" 
                  className="shrink-0" 
                  title="Copy Prompt"
                  onClick={() => {
                    navigator.clipboard.writeText(video.prompt)
                    toast.success('Prompt copied to clipboard!')
                  }}
                >
                  <Copy className="w-4 h-4" />
                </Button>
              </CardFooter>
            )}
          </Card>
        ))}
      </div>
    </div>
  )
}

