import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@/lib/supabase/server'
import { getCreditCost } from '@/lib/credits'
import { fal, WAN_MODEL_ID } from '@/lib/fal'
import { z } from 'zod'

// 1. Define Input Schema for Guardrails
const GenerateSchema = z.object({
  url: z.string().url().max(500),
  productName: z.string().min(2).max(100),
  goal: z.enum(['sales', 'awareness', 'retargeting']),
  prompt: z.string().min(10).max(1000),
  duration: z.number().refine(val => [15, 30, 45, 60].includes(val), {
    message: "Invalid duration. Must be 15, 30, 45, or 60."
  })
})

export async function POST(req: NextRequest) {
  try {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    // 2. Validate Input with Zod
    const body = await req.json()
    const result = GenerateSchema.safeParse(body)

    if (!result.success) {
      return NextResponse.json({ 
        error: 'Invalid input', 
        details: result.error.format() 
      }, { status: 400 })
    }

    const { url, productName, goal, prompt, duration } = result.data

    // 3. Rate Limiting Check (Supabase Backed)
    // Limit to 10 generations per hour for beta security
    const oneHourAgo = new Promise<string>(resolve => {
        const d = new Date()
        d.setHours(d.getHours() - 1)
        resolve(d.toISOString())
    })

    const { count, error: countError } = await (supabase
      .from('videos') as any)
      .select('id', { count: 'exact', head: true })
      .eq('user_id', user.id)
      .gt('created_at', await oneHourAgo)

    if (countError) {
      console.error('[API/Generate] Rate limit check error:', countError)
    } else if (count !== null && count >= 10) {
      return NextResponse.json({ 
        error: 'Too many requests. You have reached the hourly limit of 10 generations. Please try again in an hour.' 
      }, { status: 429 })
    }

    const requiredUnits = getCreditCost(duration)

    // 4. Atomically check and deduct credits via Postgres RPC
    const { data: newBalance, error: deductError } = await (supabase as any).rpc('deduct_credits', {
      p_user_id: user.id,
      p_amount: requiredUnits
    })

    if (deductError) {
      console.error('[API/Generate] Unit deduction RPC error:', deductError)
      return NextResponse.json({ error: 'Failed to process unit deduction. Please try again later.' }, { status: 500 })
    }

    if (newBalance === -1) {
      return NextResponse.json({ 
        error: `Insufficient units. This generation requires ${requiredUnits} units, but your balance is too low.` 
      }, { status: 402 })
    }

    // 5. Insert pending video row
    const { data: videoData, error: videoError } = await (supabase.from('videos') as any)
      .insert({
        user_id: user.id,
        prompt: prompt,
        status: 'pending',
        duration: duration,
        script: `Product: ${productName} \nURL: ${url} \nGoal: ${goal}`
      })
      .select('id')
      .single()

    if (videoError || !videoData) {
      // Revert units atomically
      await (supabase as any).rpc('increment_credits', { p_user_id: user.id, p_amount: requiredUnits })
      return NextResponse.json({ error: 'Failed to create video record' }, { status: 500 })
    }

    const videoId = videoData.id

    // 6. Submit to fal.ai (async) 
    const webhookUrl = `${process.env.NEXT_PUBLIC_APP_URL}/api/webhook/fal?videoId=${videoId}`

    const falResult = await fal.queue.submit(WAN_MODEL_ID, {
      input: {
        prompt,
        aspect_ratio: '9:16'
      },
      webhookUrl: webhookUrl
    })

    // 7. Update the record with the fal.ai job ID
    await (supabase.from('videos') as any)
      .update({
        fal_job_id: falResult.request_id,
        status: 'processing'
      })
      .eq('id', videoId)

    return NextResponse.json({ 
      success: true, 
      videoId,
      message: 'Video generation started' 
    })

  } catch (error: any) {
    console.error('Generation Error:', error)
    return NextResponse.json({ error: error.message || 'Internal server error' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { z } from 'zod'

const ScriptRequestSchema = z.object({
  url: z.string().url(),
  productName: z.string().min(1),
  goal: z.string(),
  actorDescription: z.string()
})

const DEEPSEEK_API_URL = 'https://api.deepseek.com/chat/completions'

export async function POST(req: NextRequest) {
  try {
    const apiKey = process.env.DEEPSEEK_API_KEY
    if (!apiKey || apiKey === 'your_deepseek_api_key_here') {
      return NextResponse.json({ error: 'DeepSeek API key not configured' }, { status: 500 })
    }

    const body = await req.json()
    const validated = ScriptRequestSchema.safeParse(body)

    if (!validated.success) {
      return NextResponse.json({ error: 'Invalid input', details: validated.error.format() }, { status: 400 })
    }

    const { url, productName, goal, actorDescription } = validated.data

    const systemPrompt = `You are an expert UGC (User Generated Content) scriptwriter and video prompt engineer. 
Your goal is to create a high-converting script and video prompt for a viral ad.

INPUTS:
- Product: ${productName}
- URL: ${url}
- Marketing Goal: ${goal}
- Actor: ${actorDescription}

OUTPUT FORMAT:
You must return a JSON object with exactly two fields:
1. "videoPrompt": A detailed, cinematic visual description (50-100 words) optimized for Wan 2.1 (T2V). Focus on lighting, camera movement (e.g., "high-quality cinematic tracking shot", "bokeh background"), and the actor's actions matching the UGC style.
2. "voiceoverScript": A 15-30 second high-energy spoken script (40-70 words) optimized for Voxtral (Mistral TTS). Use natural, persuasive language, hooks, and a strong call to action suitable for social media ads.

Keep the tone modern, professional, and visually stunning. 
Do not include any other text in your response, ONLY the JSON object.`

    const response = await fetch(DEEPSEEK_API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model: 'deepseek-reasoner',
        messages: [
          { role: 'system', content: 'You are a professional ad scriptwriter. Always respond with pure JSON.' },
          { role: 'user', content: systemPrompt }
        ],
        response_format: { type: 'json_object' },
        stream: false
      })
    })

    if (!response.ok) {
      const errorText = await response.text()
      console.error('DeepSeek API Error:', errorText)
      throw new Error(`DeepSeek API failed: ${response.statusText}`)
    }

    const data = await response.json()
    const content = data.choices[0].message.content

    // Parse the JSON content from DeepSeek
    try {
      const result = JSON.parse(content)
      return NextResponse.json(result)
    } catch (parseError) {
      console.error('Failed to parse DeepSeek response as JSON:', content)
      return NextResponse.json({ 
        error: 'AI generated invalid format', 
        raw: content.substring(0, 500) 
      }, { status: 500 })
    }

  } catch (error: any) {
    console.error('Script Generation Error:', error)
    return NextResponse.json({ error: error.message || 'Internal server error' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import ffmpeg from 'fluent-ffmpeg'
import axios from 'axios'
import fs from 'fs/promises'
import path from 'path'
import os from 'os'
import { createClient } from '@/lib/supabase/server'

export async function POST(req: NextRequest) {
  const tempDir = path.join(os.tmpdir(), `stitch-${Date.now()}`)

  try {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const { videoUrl, voiceScript, videoId } = await req.json()

    if (!videoUrl || !voiceScript) {
      return NextResponse.json({ error: 'Missing videoUrl or voiceScript' }, { status: 400 })
    }

    // 1. Setup temp directory
    await fs.mkdir(tempDir, { recursive: true })
    const videoPath = path.join(tempDir, 'input_video.mp4')
    const audioPath = path.join(tempDir, 'input_audio.mp3')
    const outputPath = path.join(tempDir, 'output.mp4')

    // 2. Download Video and Generate TTS Audio concurrently
    const { fal, VOXTRAL_MODEL_ID } = await import('@/lib/fal')

    const [videoRes, ttsResult] = await Promise.all([
      axios.get(videoUrl, { responseType: 'arraybuffer' }),
      fal.subscribe(VOXTRAL_MODEL_ID, {
        input: {
          text: voiceScript,
          voice: 'am_adam'
        }
      })
    ])

    const ttsAudioUrl = (ttsResult as any).audio?.url
    if (!ttsAudioUrl) {
      throw new Error('Fal AI Voxtral-TTS failed to return audio URL')
    }

    const audioRes = await axios.get(ttsAudioUrl, { responseType: 'arraybuffer' })

    await Promise.all([
      fs.writeFile(videoPath, Buffer.from(videoRes.data)),
      fs.writeFile(audioPath, Buffer.from(audioRes.data))
    ])

    // 3. Process with FFmpeg
    await new Promise((resolve, reject) => {
      ffmpeg(videoPath)
        .input(audioPath)
        .outputOptions([
          '-c:v copy',       // Copy video codec (fast)
          '-c:a aac',       // Re-encode audio to AAC
          '-map 0:v:0',      // Use video from first input
          '-map 1:a:0',      // Use audio from second input
          '-shortest'        // Trim to shortest duration
        ])
        .on('end', resolve)
        .on('error', (err) => {
          console.error('FFmpeg Error:', err)
          reject(err)
        })
        .save(outputPath)
    })

    // 4. Read the output file
    const outputBuffer = await fs.readFile(outputPath)

    // Optional: Upload to Supabase Storage in the background or here
    // ...

    // 5. Return the buffer
    return new NextResponse(outputBuffer, {
      headers: {
        'Content-Type': 'video/mp4',
        'Content-Disposition': `attachment; filename="viralugc-ad.mp4"`,
      },
    })

  } catch (error: any) {
    console.error('[API/Stitch] Stitching Error:', error)
    return NextResponse.json({ error: error.message || 'Failed to stitch video and audio' }, { status: 500 })
  } finally {
    // 6. Cleanup
    try {
      await fs.rm(tempDir, { recursive: true, force: true })
    } catch (cleanupError) {
      console.warn('[API/Stitch] Cleanup Error:', cleanupError)
    }
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { fal, VOXTRAL_MODEL_ID } from '@/lib/fal'

export async function POST(req: NextRequest) {
  try {
    const { text } = await req.json()

    if (!text) {
      return NextResponse.json({ error: 'Text is required' }, { status: 400 })
    }

    if (!process.env.FAL_KEY) {
      console.error('Missing FAL_KEY')
      return NextResponse.json({ error: 'AI services are not fully configured.' }, { status: 500 })
    }

    // Call Fal AI Voxtral-TTS
    const result: any = await fal.subscribe(VOXTRAL_MODEL_ID, {
      input: {
        text,
        voice: 'am_adam' // Using the Open Source 'Adam' equivalent in Mistral's voice set
      },
    })

    if (!result.audio?.url) {
      console.error('Fal AI Error: No audio URL returned', result)
      return NextResponse.json({ error: 'Failed to generate audio via Voxtral' }, { status: 500 })
    }

    // Fetch the audio from the generated URL to return as a buffer
    const audioRes = await fetch(result.audio.url)
    if (!audioRes.ok) {
      throw new Error('Failed to fetch generated audio from Fal storage')
    }

    const data = await audioRes.arrayBuffer()
    return new NextResponse(data, {
      headers: {
        'Content-Type': 'audio/mpeg'
      }
    })

  } catch (err: any) {
    console.error('TTS Error:', err)
    return NextResponse.json({ error: err.message || 'Internal error' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { createAdminClient } from '@/lib/supabase/admin'
import crypto from 'crypto'

export async function POST(req: NextRequest) {
  try {
    const rawBody = await req.text()

    // Webhook Signature Validation (if documented by fal.ai, usually X-Fal-Signature)
    // For simplicity of MVP, we trust the payload if the user provides the webhook,
    // but in a production environment you MUST validate the fal.ai signature.
    const searchParams = req.nextUrl.searchParams
    const videoId = searchParams.get('videoId')

    if (!videoId) {
       return NextResponse.json({ error: 'Missing videoId query parameter' }, { status: 400 })
    }

    const payload = JSON.parse(rawBody)

    // Using admin client to bypass RLS
    const supabase = createAdminClient()

    if (payload.status === 'ERROR') {
      await (supabase.from('videos') as any)
        .update({ status: 'failed' })
        .eq('id', videoId)
      return NextResponse.json({ success: true, status: 'failed set' })
    }

    // Success state
    if (payload.status === 'OK' && payload.payload?.video?.url) {
      const videoUrl = payload.payload.video.url

      // Update Supabase video record
      await (supabase.from('videos') as any)
        .update({
          video_url: videoUrl,
          status: 'completed'
        })
        .eq('id', videoId)

      return NextResponse.json({ success: true })
    }

    // Still processing/in queue
    return NextResponse.json({ success: true, message: 'Processing state received' })

  } catch (error: any) {
    console.error('Fal Webhook Error:', error)
    return NextResponse.json({ error: error.message }, { status: 500 })
  }
}

